inline bool VerifyBuffer(::flatbuffers::Verifier &verifier, const void *obj, Buffer type) {
  switch (type) {
    case Buffer_NONE: {
      return true;
    }
    case Buffer_GeoByteBuffer: {
      auto ptr = reinterpret_cast<const geo::flatbuffer::common::GeoByteBuffer *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case Buffer_GeoUbyteBuffer: {
      auto ptr = reinterpret_cast<const geo::flatbuffer::common::GeoUbyteBuffer *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case Buffer_GeoShortBuffer: {
      auto ptr = reinterpret_cast<const geo::flatbuffer::common::GeoShortBuffer *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case Buffer_GeoUshortBuffer: {
      auto ptr = reinterpret_cast<const geo::flatbuffer::common::GeoUshortBuffer *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case Buffer_GeoIntBuffer: {
      auto ptr = reinterpret_cast<const geo::flatbuffer::common::GeoIntBuffer *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case Buffer_GeoUintBuffer: {
      auto ptr = reinterpret_cast<const geo::flatbuffer::common::GeoUintBuffer *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case Buffer_GeoFloatBuffer: {
      auto ptr = reinterpret_cast<const geo::flatbuffer::common::GeoFloatBuffer *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case Buffer_GeoDoubleBuffer: {
      auto ptr = reinterpret_cast<const geo::flatbuffer::common::GeoDoubleBuffer *>(obj);
      return verifier.VerifyTable(ptr);
    }
    default: return true;
  }
}

inline bool VerifyBufferVector(::flatbuffers::Verifier &verifier, const ::flatbuffers::Vector<::flatbuffers::Offset<void>> *values, const ::flatbuffers::Vector<uint8_t> *types) {
  if (!values || !types) return !values && !types;
  if (values->size() != types->size()) return false;
  for (::flatbuffers::uoffset_t i = 0; i < values->size(); ++i) {
    if (!VerifyBuffer(
        verifier,  values->Get(i), types->GetEnum<Buffer>(i))) {
      return false;
    }
  }
  return true;
}

